1	/**
2	 * GoogleGeminiAdapter — direct Gemini Developer API integration via `@google/genai`.
3	 *
4	 * This is intentionally separate from `VertexGeminiAdapter`. Some Gemini API
5	 * models can appear in the admin model catalog before the configured Vertex
6	 * project/region can serve them. Routes with provider `google` call the
7	 * Gemini API with an API key; routes with provider `vertex` keep using ADC,
8	 * Vertex regions, explicit caches, and Vertex Batch Prediction.
9	 */
10	
11	import { GoogleGenAI, ThinkingLevel } from '@google/genai';
12	import type { Content, GenerateContentResponse, Part } from '@google/genai';
13	import { createSign } from 'node:crypto';
14	import type { OracleObjectResult, OracleTextResult, OracleUsage } from '../client/types';
15	import type { ReasoningEffort } from '../routes';
16	import type {
17	  GenerateObjectArgs,
18	  GenerateTextArgs,
19	  OracleProviderAdapter,
20	} from './types';
21	import {
22	  flattenPlan,
23	  parseJsonOrRaw,
24	  tryZodParse,
25	  zodToJsonSchema,
26	} from './vertex-gemini-adapter';
27	
28	export interface GoogleGeminiAdapterOptions {
29	  /** Gemini API key. Defaults to GEMINI_API_KEY, then GOOGLE_API_KEY. */
30	  apiKey?: string;
31	}
32	
33	export class GoogleGeminiAdapter implements OracleProviderAdapter {
34	  readonly provider = 'google' as const;
35	  private readonly client: GoogleGenAI | null;
36	  private readonly serviceAccountJson: string | null;
37	
38	  constructor(opts: GoogleGeminiAdapterOptions = {}) {
39	    const apiKey = opts.apiKey ?? process.env.GEMINI_API_KEY ?? process.env.GOOGLE_API_KEY;
40	    this.serviceAccountJson = process.env.GOOGLE_APPLICATION_CREDENTIALS_JSON ?? null;
41	    if (!apiKey && !this.serviceAccountJson) {
42	      throw new Error(
43	        'GoogleGeminiAdapter: GEMINI_API_KEY or GOOGLE_APPLICATION_CREDENTIALS_JSON is not set. Set one for google/* routes.',
44	      );
45	    }
46	    this.client = apiKey ? new GoogleGenAI({ apiKey }) : null;
47	  }
48	
49	  async generateText(args: GenerateTextArgs): Promise<OracleTextResult> {
50	    const { plan, route, providerOptions } = args;
51	    const { systemPrompt, userMessage } = flattenPlan(plan);
52	    const callStartedAt = Date.now();
53	
54	    const contents = buildContents(userMessage, providerOptions);
55	    const generationConfig = {
56	      temperature:
57	        typeof providerOptions?.temperature === 'number'
58	          ? providerOptions.temperature
59	          : undefined,
60	      maxOutputTokens:
61	        typeof providerOptions?.maxOutputTokens === 'number'
62	          ? providerOptions.maxOutputTokens
63	          : undefined,
64	      ...geminiThinkingConfig(route.reasoningEffort),
65	    };
66	    const response = this.client
67	      ? await this.client.models.generateContent({
68	          model: route.modelId,
69	          contents,
70	          config: {
71	            systemInstruction: systemPrompt || undefined,
72	            ...generationConfig,
73	          },
74	        })
75	      : await this.generateContentWithOAuth({
76	          modelId: route.modelId,
77	          contents,
78	          systemPrompt,
79	          generationConfig,
80	        });
81	
82	    return {
83	      text: extractTextFromGeminiResponse(response),
84	      usage: normalizeGeminiUsage(response, Date.now() - callStartedAt),
85	      rawResponse: response,
86	    };
87	  }
88	
89	  async generateObject<TSchema, TOutput>(
90	    args: GenerateObjectArgs<TSchema>,
91	  ): Promise<OracleObjectResult<TOutput>> {
92	    const { plan, route, schema, providerOptions } = args;
93	    const { systemPrompt, userMessage } = flattenPlan(plan);
94	    const callStartedAt = Date.now();
95	
96	    const contents: Content[] = [{ role: 'user', parts: [{ text: userMessage }] }];
97	    const jsonSchema = zodToJsonSchema(schema);
98	    const commonConfig = {
99	      temperature: 0.1,
100	      // Output-token budget so a dense extraction doesn't truncate the JSON
101	      // (truncated JSON parses as a raw string and fails the schema).
102	      ...(typeof providerOptions?.maxOutputTokens === 'number'
103	        ? { maxOutputTokens: providerOptions.maxOutputTokens }
104	        : {}),
105	      ...geminiThinkingConfig(route.reasoningEffort),
106	    };
107	    const sdkConfig = {
108	      ...commonConfig,
109	      responseMimeType: 'application/json',
110	      responseJsonSchema: jsonSchema as unknown,
111	    };
112	    const restConfig = {
113	      ...commonConfig,
114	      responseMimeType: 'application/json',
115	      responseSchema: toGeminiRestSchema(jsonSchema),
116	    };
117	    const response = this.client
118	      ? await this.client.models.generateContent({
119	          model: route.modelId,
120	          contents,
121	          config: sdkConfig,
122	        })
123	      : await this.generateContentWithOAuth({
124	          modelId: route.modelId,
125	          contents,
126	          systemPrompt,
127	          generationConfig: restConfig,
128	        });
129	
130	    const text = extractTextFromGeminiResponse(response);
131	    const parsed = parseJsonOrRaw(text);
132	    const validated = tryZodParse<TOutput>(schema, parsed);
133	
134	    return {
135	      object: (validated ?? parsed) as TOutput,
136	      usage: normalizeGeminiUsage(response, Date.now() - callStartedAt),
137	      rawResponse: response,
138	    };
139	  }
140	
141	  private async generateContentWithOAuth(input: {
142	    modelId: string;
143	    contents: Content[];
144	    systemPrompt: string;
145	    generationConfig: Record<string, unknown>;
146	  }): Promise<GenerateContentResponse> {
147	    if (!this.serviceAccountJson) {
148	      throw new Error('GoogleGeminiAdapter: service account JSON missing for OAuth request.');
149	    }
150	    const token = await getGenerativeLanguageAccessToken(this.serviceAccountJson);
151	    const res = await fetch(
152	      `https://generativelanguage.googleapis.com/v1beta/models/${input.modelId}:generateContent`,
153	      {
154	        method: 'POST',
155	        headers: {
156	          Authorization: `Bearer ${token}`,
157	          'Content-Type': 'application/json',
158	          Accept: 'application/json',
159	        },
160	        body: JSON.stringify({
161	          contents: input.contents,
162	          systemInstruction: input.systemPrompt
163	            ? { parts: [{ text: input.systemPrompt }] }
164	            : undefined,
165	          generationConfig: stripUndefined(input.generationConfig),
166	        }),
167	        signal: AbortSignal.timeout(60_000),
168	      },
169	    );
170	    if (!res.ok) {
171	      throw new Error(`Gemini API generateContent failed: ${res.status} ${await res.text()}`);
172	    }
173	    return (await res.json()) as GenerateContentResponse;
174	  }
175	}
176	
177	function buildContents(
178	  userMessage: string,
179	  providerOptions?: Record<string, unknown>,
180	): Content[] {
181	  const messages = providerOptions?.messages as
182	    | Array<{ role: 'user' | 'assistant' | 'system'; content: unknown }>
183	    | undefined;
184	  if (Array.isArray(messages) && messages.length > 0) {
185	    return messages
186	      .filter((m) => m.role !== 'system')
187	      .map((m) => ({
188	        role: m.role === 'assistant' ? 'model' : 'user',
189	        parts: toGeminiParts(m.content),
190	      }));
191	  }
192	  return [{ role: 'user', parts: [{ text: userMessage }] }];
193	}
194	
195	function toGeminiParts(content: unknown): Part[] {
196	  if (typeof content === 'string') return [{ text: content }];
197	  if (!Array.isArray(content)) return [{ text: String(content ?? '') }];
198	  const parts: Part[] = [];
199	  for (const raw of content) {
200	    if (raw && typeof raw === 'object') {
201	      const part = raw as Record<string, unknown>;
202	      if (
203	        part.type === 'image' &&
204	        typeof part.data === 'string' &&
205	        typeof part.mimeType === 'string'
206	      ) {
207	        parts.push({ inlineData: { mimeType: part.mimeType, data: part.data } });
208	        continue;
209	      }
210	      if ((part.type === 'text' || part.type === undefined) && typeof part.text === 'string') {
211	        parts.push({ text: part.text });
212	        continue;
213	      }
214	    }
215	    parts.push({ text: String(raw) });
216	  }
217	  return parts;
218	}
219	
220	function geminiThinkingConfig(effort: ReasoningEffort | undefined):
221	  | { thinkingConfig: { thinkingLevel: ThinkingLevel } }
222	  | Record<string, never> {
223	  if (!effort) return {};
224	  const thinkingLevel =
225	    effort === 'off' ? ThinkingLevel.MINIMAL
226	      : effort === 'low' ? ThinkingLevel.LOW
227	      : effort === 'medium' ? ThinkingLevel.MEDIUM
228	      : ThinkingLevel.HIGH;
229	  return { thinkingConfig: { thinkingLevel } };
230	}
231	
232	function normalizeGeminiUsage(
233	  response: GenerateContentResponse,
234	  latencyMs: number,
235	): OracleUsage {
236	  const u = response.usageMetadata ?? {};
237	  return {
238	    inputTokens: u.promptTokenCount,
239	    outputTokens: u.candidatesTokenCount,
240	    cachedInputTokens: u.cachedContentTokenCount,
241	    reasoningTokens: u.thoughtsTokenCount,
242	    latencyMs,
243	    providerRequestId: response.responseId,
244	    rawUsageJson: u,
245	  };
246	}
247	
248	function extractTextFromGeminiResponse(response: GenerateContentResponse): string {
249	  if (typeof response.text === 'string') return response.text;
250	  const candidateText = response.candidates
251	    ?.flatMap((candidate) => candidate.content?.parts ?? [])
252	    .map((part) => ('text' in part && typeof part.text === 'string' ? part.text : ''))
253	    .join('');
254	  return candidateText ?? '';
255	}
256	
257	async function getGenerativeLanguageAccessToken(saJson: string): Promise<string> {
258	  const sa = parseServiceAccountJson(saJson);
259	  const now = Math.floor(Date.now() / 1000);
260	
261	  const header = Buffer.from(JSON.stringify({ alg: 'RS256', typ: 'JWT' })).toString('base64url');
262	  const payload = Buffer.from(
263	    JSON.stringify({
264	      iss: sa.client_email,
265	      scope: 'https://www.googleapis.com/auth/generative-language',
266	      aud: 'https://oauth2.googleapis.com/token',
267	      iat: now,
268	      exp: now + 3600,
269	    }),
270	  ).toString('base64url');
271	
272	  const signer = createSign('SHA256');
273	  signer.update(`${header}.${payload}`);
274	  const sig = signer.sign({ key: sa.private_key, format: 'pem' }, 'base64url');
275	  const jwt = `${header}.${payload}.${sig}`;
276	
277	  const res = await fetch('https://oauth2.googleapis.com/token', {
278	    method: 'POST',
279	    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
280	    body: new URLSearchParams({
281	      grant_type: 'urn:ietf:params:oauth:grant-type:jwt-bearer',
282	      assertion: jwt,
283	    }),
284	    signal: AbortSignal.timeout(10_000),
285	  });
286	  if (!res.ok) {
287	    throw new Error(`Google token exchange failed: ${res.status} ${await res.text()}`);
288	  }
289	  const data = (await res.json()) as { access_token: string };
290	  return data.access_token;
291	}
292	
293	function parseServiceAccountJson(saJson: string): { client_email: string; private_key: string } {
294	  try {
295	    return JSON.parse(saJson) as { client_email: string; private_key: string };
296	  } catch {
297	    // Vercel env pulls can materialize the PEM as literal newlines inside the
298	    // JSON string. Normalize just that field, then parse normally.
299	    const normalized = saJson.replace(
300	      /"private_key"\s*:\s*"([\s\S]*?)"/,
301	      (_match, key: string) => `"private_key":"${key.replace(/\r?\n/g, '\\n')}"`,
302	    );
303	    return JSON.parse(normalized) as { client_email: string; private_key: string };
304	  }
305	}
306	
307	function stripUndefined<T extends Record<string, unknown>>(obj: T): Record<string, unknown> {
308	  return Object.fromEntries(Object.entries(obj).filter(([, value]) => value !== undefined));
309	}
310	
311	function toGeminiRestSchema(schema: unknown): unknown {
312	  if (Array.isArray(schema)) return schema.map(toGeminiRestSchema);
313	  if (!schema || typeof schema !== 'object') return schema;
314	
315	  const output: Record<string, unknown> = {};
316	  for (const [key, value] of Object.entries(schema)) {
317	    if (key === '$schema' || key === 'additionalProperties') continue;
318	    output[key] = toGeminiRestSchema(value);
319	  }
320	  return output;
321	}
