1	import { eq, inArray } from 'drizzle-orm';
2	import type { OracleDb } from '@oracle/db';
3	import { modelCapabilities, settings } from '@oracle/db/schema';
4	import { getAuxiliaryModelDef } from './auxiliary';
5	import {
6	  ENFORCE_MODEL_CAPABILITIES_SETTING_KEY,
7	  MODEL_POOL_SETTING_KEYS,
8	  REASONING_EFFORT_SETTING_KEYS,
9	  ROUTE_SETTING_KEYS,
10	} from './defaults';
11	import { ModelCapabilityError, NoConfiguredModelError, type ModelSlot } from './errors';
12	import { missingRequirements } from './capability-requirements';
13	import { providerModelIdForRoute, resolveModelRoute, type SyntheticRouteCaps } from './resolve';
14	import type { ModelCapability } from '../model-capabilities/types';
15	import type { OracleModelRole, OracleModelRoute, ReasoningEffort } from './types';
16	
17	export interface RouteCandidate {
18	  route: OracleModelRoute;
19	  slot: ModelSlot;
20	  isPrimary: boolean;
21	  approvedModelId: string;
22	}
23	
24	export interface SkippedRouteCandidate {
25	  slot: ModelSlot;
26	  modelIdOrRouteId: string;
27	  reason: string;
28	}
29	
30	export interface RouteCandidateResolution {
31	  slot: ModelSlot;
32	  candidates: RouteCandidate[];
33	  skipped: SkippedRouteCandidate[];
34	}
35	
36	function isReasoningEffort(v: unknown): v is ReasoningEffort {
37	  return v === 'off' || v === 'low' || v === 'medium' || v === 'high';
38	}
39	
40	function isPipelineSlot(slot: ModelSlot): slot is OracleModelRole {
41	  return slot === 'interview' || slot === 'extraction' || slot === 'synthesis';
42	}
43	
44	function roleForSlot(slot: ModelSlot): OracleModelRole {
45	  return isPipelineSlot(slot) ? slot : 'extraction';
46	}
47	
48	function settingKeysForSlot(slot: ModelSlot): {
49	  routeKey: string;
50	  effortKey?: string;
51	  poolKey?: string;
52	} {
53	  if (isPipelineSlot(slot)) {
54	    return {
55	      routeKey: ROUTE_SETTING_KEYS[slot],
56	      effortKey: REASONING_EFFORT_SETTING_KEYS[slot],
57	      poolKey: MODEL_POOL_SETTING_KEYS[slot],
58	    };
59	  }
60	  const def = getAuxiliaryModelDef(slot);
61	  if (!def) throw new NoConfiguredModelError(slot, 'unknown auxiliary model id');
62	  return {
63	    routeKey: def.routeSettingKey,
64	    effortKey: def.reasoningEffortSettingKey,
65	  };
66	}
67	
68	function capToRouteCaps(cap: ModelCapability): SyntheticRouteCaps {
69	  const normalized = normalizeProviderCapabilities(cap);
70	  return {
71	    supportsVision: normalized.vision,
72	    supportsToolCalling: normalized.toolCalling,
73	    supportsStructuredOutput: normalized.structuredOutputs,
74	    supportsReasoningControls: normalized.thinking,
75	    enabled: true,
76	  };
77	}
78	
79	function isQwenVisionModel(id: string): boolean {
80	  const lower = id.toLowerCase();
81	  return lower.includes('-vl') || lower.includes('/vl-') || lower.includes('omni');
82	}
83	
84	/**
85	 * Runtime guards must be stricter than third-party catalog enrichment. Qwen's
86	 * text-only models can be over-tagged at the family level; only VL/omni models
87	 * should satisfy the image-vision slot.
88	 */
89	function normalizeProviderCapabilities(cap: ModelCapability): ModelCapability {
90	  if (cap.provider === 'qwen' && cap.vision && !isQwenVisionModel(cap.id)) {
91	    return { ...cap, vision: false };
92	  }
93	  return cap;
94	}
95	
96	function catalogIdsForRoute(route: OracleModelRoute): string[] {
97	  const ids = [providerModelIdForRoute(route)];
98	  if (route.provider === 'vertex') ids.push(`google/${route.modelId}`);
99	  return ids;
100	}
101	
102	async function readSettings(db: OracleDb, keys: string[]): Promise<Map<string, unknown>> {
103	  const rows = await db
104	    .select({ key: settings.key, value: settings.value })
105	    .from(settings)
106	    .where(inArray(settings.key, keys));
107	  return new Map(rows.map((r) => [r.key, r.value]));
108	}
109	
110	async function loadCapabilityMap(db: OracleDb, ids: string[]): Promise<Map<string, ModelCapability>> {
111	  if (ids.length === 0) return new Map();
112	  const unique = Array.from(new Set(ids));
113	  const rows = await db
114	    .select()
115	    .from(modelCapabilities)
116	    .where(inArray(modelCapabilities.id, unique));
117	  return new Map(
118	    rows.map((r) => [
119	      r.id,
120	      {
121	        id: r.id,
122	        provider: r.provider as ModelCapability['provider'],
123	        displayName: r.displayName,
124	        contextLength: r.contextLength,
125	        maxOutputTokens: r.maxOutputTokens,
126	        promptPer1mUsd: r.promptPer1mUsd != null ? Number(r.promptPer1mUsd) : null,
127	        completionPer1mUsd: r.completionPer1mUsd != null ? Number(r.completionPer1mUsd) : null,
128	        vision: r.vision,
129	        pdf: r.pdf,
130	        thinking: r.thinking,
131	        structuredOutputs: r.structuredOutputs,
132	        toolCalling: r.toolCalling,
133	        promptCaching: r.promptCaching,
134	        outputCap: r.outputCap,
135	        knowledgeCutoff: r.knowledgeCutoff,
136	        source: r.source as ModelCapability['source'],
137	      } satisfies ModelCapability,
138	    ]),
139	  );
140	}
141	
142	async function enforceCapabilitiesEnabled(db: OracleDb): Promise<boolean> {
143	  const rows = await db
144	    .select({ value: settings.value })
145	    .from(settings)
146	    .where(eq(settings.key, ENFORCE_MODEL_CAPABILITIES_SETTING_KEY))
147	    .limit(1);
148	  return rows[0]?.value !== false;
149	}
150	
151	function capabilityForRoute(
152	  route: OracleModelRoute,
153	  capabilityMap: Map<string, ModelCapability>,
154	): { id: string; cap: ModelCapability } | null {
155	  for (const id of catalogIdsForRoute(route)) {
156	    const cap = capabilityMap.get(id);
157	    if (cap) return { id, cap };
158	  }
159	  return null;
160	}
161	
162	function resolveWithKnownCaps(
163	  modelIdOrRouteId: string,
164	  role: OracleModelRole,
165	  effort: ReasoningEffort | undefined,
