// Replicate stripIncompatibleFields walk
function walk(node: unknown): void {
  if (node === null || typeof node !== 'object') return;
  if (Array.isArray(node)) { for (const i of node) walk(i); return; }
  const obj = node as Record<string, unknown>;
  delete obj.$schema; delete obj.default;
  const props = obj.properties;
  if (props !== null && typeof props === 'object' && !Array.isArray(props)) {
    obj.required = Object.keys(props as Record<string, unknown>);
  }
  for (const v of Object.values(obj)) walk(v);
}

const raw = z.toJSONSchema(ExtractionOutputSchema as any);
const cloned = JSON.parse(JSON.stringify(raw));
walk(cloned);

// Validate: every object with properties must have required ⊇ keys and additionalProperties:false
const problems: string[] = [];
function check(node: unknown, path: string): void {
  if (node === null || typeof node !== 'object') return;
  if (Array.isArray(node)) { node.forEach((n,i)=>check(n,`${path}[${i}]`)); return; }
  const o = node as Record<string, any>;
  if (o.properties && typeof o.properties === 'object' && !Array.isArray(o.properties)) {
    const keys = Object.keys(o.properties);
    const req = new Set(o.required ?? []);
    const missing = keys.filter(k=>!req.has(k));
    if (missing.length) problems.push(`${path}: required missing ${missing.join(',')}`);
    if (o.additionalProperties !== false) problems.push(`${path}: additionalProperties=${JSON.stringify(o.additionalProperties)}`);
  }
  for (const [k,v] of Object.entries(o)) check(v, `${path}.${k}`);
}
check(cloned, '$');
console.log('uses $ref/$defs:', JSON.stringify(raw).includes('$ref'));
console.log('PROBLEMS:', problems.length ? problems : 'none');
EOF
