/**
 * Unified model capability shape used by the admin model-pool + picker UIs.
 *
 * Model list: sourced from the 3 direct provider APIs (Anthropic, OpenAI,
 * Google Gemini). Pricing and capability flags are enriched from OpenRouter's
 * /v1/models endpoint and joined onto those models before DB persistence.
 */

export type ModelProvider = 'anthropic' | 'openai' | 'google' | 'deepseek' | 'qwen';

export type ModelCapabilitySource =
  | 'anthropic_api'   // model listed by Anthropic /v1/models
  | 'openai_api'      // model listed by OpenAI /v1/models
  | 'google_api'      // model listed by Google generativelanguage.googleapis.com/v1beta/models
  | 'deepseek_api'    // model listed by DeepSeek /models
  | 'qwen_api';       // model listed by DashScope OpenAI-compatible /models

export interface ModelCapability {
  /** "provider/modelId" — same id format used in settings.model_pool_*. */
  id: string;
  provider: ModelProvider;
  displayName: string;

  contextLength: number | null;       // max input tokens
  maxOutputTokens: number | null;     // max output tokens per request

  /** USD per 1,000,000 input tokens. */
  promptPer1mUsd: number | null;
  /** USD per 1,000,000 output tokens. */
  completionPer1mUsd: number | null;

  vision: boolean;
  pdf: boolean;
  thinking: boolean;
  structuredOutputs: boolean;
  toolCalling: boolean;
  promptCaching: boolean;
  /** Model supports an output-length cap (max_completion_tokens or max_tokens). */
  outputCap: boolean;

  /** ISO date string (YYYY-MM-DD), if the provider published it. */
  knowledgeCutoff: string | null;

  source: ModelCapabilitySource;
}

/**
 * Translate unified ReasoningEffort to Vertex Gemini 2.5+'s thinkingConfig.
 * Returns an object you can spread into the request `config`.
 *
 * Budgets (Gemini 2.5 Pro/Flash):
 *   off    → thinkingBudget: 0  (disables thinking)
 *   low    → 1024
 *   medium → 8192
 *   high   → 24576 (Flash hard cap; Pro accepts up to 32768)
 *
 * Models without thinking support (1.x family) ignore the param silently.
 */
function vertexThinkingConfig(effort: ReasoningEffort | undefined):
  | { thinkingConfig: { thinkingBudget: number } }
  | Record<string, never> {
  if (!effort) return {};
  const budget =
    effort === 'off' ? 0
      : effort === 'low' ? 1024
      : effort === 'medium' ? 8192
      : 24576;
  return { thinkingConfig: { thinkingBudget: budget } };
}

/**

/**
 * Dynamic model route resolver.
 *
 * Handles two ID formats:
 *   1. Catalog routeId, e.g. "anthropic_claude_haiku_4_5_interview_primary"
 *   2. Provider/model id, e.g. "anthropic/claude-haiku-4-5"
 *
 * This resolver is synchronous and cannot read model_capabilities. Production
 * settings should use the DB-aware candidate resolver, which passes verified
 * capability flags into synthetic routes and enforces slot requirements.
 */

import type { OracleModelRole, OracleModelRoute, OracleProvider, ReasoningEffort } from './types';
import { ORACLE_MODEL_ROUTES, getOracleRoute } from './catalog';

const OR_PROVIDER_MAP: Record<string, OracleProvider> = {
  anthropic: 'anthropic',
  openai: 'openai',
  google: 'google',
  deepseek: 'deepseek',
  qwen: 'qwen',
};

function mapPrefix(prefix: string): OracleProvider | null {
  return (OR_PROVIDER_MAP[prefix] ?? null) as OracleProvider | null;
}

const SYNTHETIC_CAPS: Pick<
  OracleModelRoute,
  | 'supportsVision'
  | 'supportsStreaming'
  | 'supportsToolCalling'
  | 'supportsStructuredOutput'
  | 'supportsReasoningControls'
  | 'costTier'
  | 'enabled'
> = {
  supportsVision: true,
  supportsStreaming: true,
  supportsToolCalling: true,
  supportsStructuredOutput: true,
  supportsReasoningControls: false,
  costTier: 'balanced_default',
  enabled: true,
};

export type SyntheticRouteCaps = Partial<typeof SYNTHETIC_CAPS>;

function makeSyntheticRoute(
  providerModelId: string,
  provider: OracleProvider,
  modelId: string,
  role: OracleModelRole,
  caps?: SyntheticRouteCaps,
): OracleModelRoute {
  const cacheStrategy =
    provider === 'anthropic'
      ? 'anthropic_auto_plus_explicit'
      : provider === 'vertex'
        ? 'vertex_implicit_or_explicit_by_context_size'
        : provider === 'google'
          ? 'none'
          : provider === 'deepseek'
            ? 'deepseek_automatic_prefix'
            : provider === 'qwen'
              ? 'qwen_explicit_context_cache'
              : 'openai_automatic_with_cache_key';

  const structuredOutputStrategy =
    provider === 'vertex' || provider === 'google'
      ? 'native_json_schema'
      : provider === 'openai'
        ? 'native_json_schema'
        : 'tool_call';

  if (!caps) {
    console.warn(
      `[resolve] using synthetic route for "${providerModelId}" (role=${role}) without DB-verified capabilities. ` +
        `Production settings should use resolveRouteCandidates().`,
    );
  }

  return {
    routeId: providerModelId,
    role,
    tier: 'primary',
    internalPurpose: null,
    provider,
    modelId,
    displayName: providerModelId,
    recommendedUse: `Dynamically resolved from model pool (${providerModelId}).`,
    cacheStrategy,
    structuredOutputStrategy,
    ...SYNTHETIC_CAPS,
    ...(caps ?? {}),
  };
}

export function providerModelIdForRoute(route: OracleModelRoute): string {
  return `${route.provider}/${route.modelId}`;
}

export function resolveModelRoute(
  modelIdOrRouteId: string,
  role: OracleModelRole,
  reasoningEffort?: ReasoningEffort,
  caps?: SyntheticRouteCaps,
): OracleModelRoute | null {
  let base: OracleModelRoute | null = null;

  const byRouteId = getOracleRoute(modelIdOrRouteId);
  if (byRouteId) {
    base = byRouteId;
  } else {
    const slashIdx = modelIdOrRouteId.indexOf('/');
    if (slashIdx === -1) return null;

    const prefix = modelIdOrRouteId.slice(0, slashIdx);
    const modelId = modelIdOrRouteId.slice(slashIdx + 1);
    const provider = mapPrefix(prefix);
    if (!provider) return null;

    const catalogMatch = Object.values(ORACLE_MODEL_ROUTES).find(
      (r) => r.provider === provider && r.modelId === modelId && r.role === role,
    );
    base = catalogMatch ?? makeSyntheticRoute(modelIdOrRouteId, provider, modelId, role, caps);
  }

  return reasoningEffort ? { ...base, reasoningEffort } : base;
}

