1	/**
2	 * R-providers smoke runner.
3	 *
4	 * Fires generateText + generateObject against each direct provider adapter
5	 * with a minimal fixture plan. Confirms:
6	 *   - The adapter connects to the real provider (Vertex / Anthropic / OpenAI).
7	 *   - Structured-output schema parsing works.
8	 *   - Usage tokens normalize correctly.
9	 *
10	 * Usage (from repo root):
11	 *   pnpm --filter @oracle/ai tsx src/__verify__/r-providers-smoke.ts vertex
12	 *   pnpm --filter @oracle/ai tsx src/__verify__/r-providers-smoke.ts anthropic
13	 *   pnpm --filter @oracle/ai tsx src/__verify__/r-providers-smoke.ts openai
14	 *   pnpm --filter @oracle/ai tsx src/__verify__/r-providers-smoke.ts all
15	 *
16	 * Costs roughly $0.001 per provider per run.
17	 */
18	
19	import { config as loadEnv } from 'dotenv';
20	import { dirname, resolve } from 'node:path';
21	import { fileURLToPath } from 'node:url';
22	import { z } from 'zod';
23	import { AnthropicAdapter } from '../providers/anthropic-adapter';
24	import { OpenAIAdapter } from '../providers/openai-adapter';
25	import { VertexGeminiAdapter } from '../providers/vertex-gemini-adapter';
26	import type {
27	  OracleObjectResult,
28	  OraclePromptPlan,
29	  OracleTextResult,
30	} from '../client/types';
31	import type { OracleModelRoute, OracleProvider } from '../routes';
32	
33	const __dirname = dirname(fileURLToPath(import.meta.url));
34	const repoRoot = resolve(__dirname, '..', '..', '..', '..');
35	// override: true so .env.local wins over any shell-level empty placeholders
36	// (some harnesses inject ANTHROPIC_API_KEY="" / OPENAI_API_KEY="" as a
37	// credential-redaction safeguard, which would otherwise mask our real keys).
38	loadEnv({ path: resolve(repoRoot, '.env.local'), override: true });
39	loadEnv({ path: resolve(repoRoot, '.env'), override: false });
40	
41	// ─── Fixture data ──────────────────────────────────────────────────────────
42	
43	const fixturePlan: OraclePromptPlan = {
44	  taskType: 'message_claim_extraction',
45	  routeId: 'smoke-fixture',
46	  promptVersion: 'smoke-1',
47	  blocks: [
48	    {
49	      id: 'sys',
50	      label: 'system',
51	      kind: 'stable_system',
52	      content:
53	        'You are a helpful assistant. Reply concisely. When asked to return structured output, always include both fields exactly as requested.',
54	      hash: 'h-sys',
55	      cacheEligible: true,
56	      reasonIncluded: 'smoke test system prompt',
57	    },
58	    {
59	      id: 'user',
60	      label: 'user-input',
