import { GoogleGenAI, ThinkingLevel } from '@google/genai';

const apiKey = process.env.GEMINI_API_KEY;
if (!apiKey) { console.error('no GEMINI_API_KEY'); process.exit(2); }
const ai = new GoogleGenAI({ apiKey });

// 1x1 transparent PNG (base64) for the vision-input hypothesis
const PNG_1x1 = 'iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYPhfDwAChwGA60e6kgAAAABJRU5ErkJggg==';

async function probe(model: string, label: string, config: any, withImage = false) {
  const contents: any = withImage
    ? [{ role: 'user', parts: [{ inlineData: { mimeType: 'image/png', data: PNG_1x1 } }, { text: 'Reply with the single word: ok' }] }]
    : 'Reply with the single word: ok';
  try {
    const r = await ai.models.generateContent({ model, contents, config });
    const txt = (r.text ?? '').slice(0, 30).replace(/\n/g, ' ');
    console.log(`  OK   [${label}] -> "${txt}" thoughts=${r.usageMetadata?.thoughtsTokenCount ?? 0}`);
  } catch (e: any) {
    console.log(`  FAIL [${label}] -> ${String(e?.message ?? e).slice(0, 160).replace(/\n/g, ' ')}`);
  }
}

async function run() {
  // discover what this key serves
  console.log('=== available models (gemini, generateContent) ===');
  const names: string[] = [];
  try {
    const pager = await ai.models.list();
    for await (const m of pager) {
      const n = (m as any).name?.replace(/^models\//, '') ?? '';
      if (n.includes('gemini') && (m as any).supportedActions?.includes?.('generateContent') !== false) names.push(n);
    }
  } catch (e: any) { console.log('list failed:', e?.message); }
  const interesting = names.filter(n => /gemini-(2\.5|3)/.test(n)).slice(0, 40);
  console.log(interesting.join(', ') || '(none listed)');

  for (const model of ['gemini-2.5-flash', 'gemini-3-flash-lite', 'gemini-3-pro-preview', 'gemini-flash-lite-latest']) {
    console.log(`\n=== ${model} ===`);
    await probe(model, 'no-thinking (text)', {});
    await probe(model, 'thinkingLevel=MEDIUM (text)', { thinkingConfig: { thinkingLevel: ThinkingLevel.MEDIUM } });
    await probe(model, 'thinkingBudget=8192 (text)', { thinkingConfig: { thinkingBudget: 8192 } });
    await probe(model, 'thinkingBudget=0 (text)', { thinkingConfig: { thinkingBudget: 0 } });
    await probe(model, 'thinkingLevel=MEDIUM (image)', { thinkingConfig: { thinkingLevel: ThinkingLevel.MEDIUM } }, true);
    await probe(model, 'thinkingBudget=8192 (image)', { thinkingConfig: { thinkingBudget: 8192 } }, true);
  }
}
run().then(() => process.exit(0)).catch(e => { console.error(e); process.exit(1); });
