cat > packages/ai/src/__verify__/_live_bugfix_proof.mts <<'EOF'
import { OpenAIAdapter } from '../providers/openai-adapter';
import { GoogleGeminiAdapter } from '../providers/google-gemini-adapter';
import { ExtractionOutputSchema, EXTRACTION_SYSTEM_PROMPT } from '../prompts/extraction-system';
import { resolveModelRoute } from '../routes/resolve';
import type { OraclePromptPlan } from '../client/types';

const TRANSCRIPT = `CONVERSATION SEGMENT TO EXTRACT FROM:
Extract claims only from the messages in this segment. Evidence quotes must use these chunk IDs only.
---
Message ID: doc-chunk-1
Content: After the licensor approves the concept, Design uploads the artwork to Coldlion and sends it to the China factory. Mass production cannot begin until Gina approves the PPS sample. If the audit fails, the team reverts to re-sampling before proceeding.
---`;

function plan(system: string, user: string): OraclePromptPlan {
  return {
    taskType: 'message_claim_extraction',
    routeId: 'verify', promptVersion: 'v1',
    blocks: [
      { id: 'sys', label: 'system', kind: 'stable_system', content: system, hash: 'h1', cacheEligible: true, reasonIncluded: 'x' },
      { id: 'usr', label: 'user-input', kind: 'dynamic_input', content: user, hash: 'h2', cacheEligible: false, reasonIncluded: 'x' },
    ],
    metadata: { stablePrefixHash: 'a', dynamicInputHash: 'b' },
  } as OraclePromptPlan;
}

const PNG = 'iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYPhfDwAChwGA60e6kgAAAABJRU5ErkJggg==';

let failures = 0;
function check(name: string, ok: boolean, detail = '') { console.log(`  ${ok ? 'PASS' : 'FAIL'}  ${name}${detail ? ' :: ' + detail : ''}`); if (!ok) failures++; }

async function bug1(model: string) {
  console.log(`\n### BUG 1 — OpenAI strict extraction: ${model}`);
  const route = resolveModelRoute(`openai/${model}`, 'extraction', undefined, { supportsStructuredOutput: true, supportsVision: true })!;
  const adapter = new OpenAIAdapter();
  try {
    const t0 = Date.now();
    const r = await adapter.generateObject({ plan: plan(EXTRACTION_SYSTEM_PROMPT, TRANSCRIPT), route, schema: ExtractionOutputSchema as any });
    const obj: any = r.object;
    const nClaims = Array.isArray(obj?.claims) ? obj.claims.length : -1;
    // Confirm optional fields legitimately absent on at least one claim (null round-trip OK)
    const omitted = (obj?.claims ?? []).some((c: any) => c.semanticRole == null || c.proposedEntities == null || c.sensitivityFlags == null);
    check(`${model} generateObject no-400 + schema-valid`, nClaims >= 1, `claims=${nClaims} ${Date.now()-t0}ms tok=${r.usage.inputTokens}/${r.usage.outputTokens}`);
    check(`${model} optional fields round-trip (some omitted/null accepted by Zod)`, omitted || nClaims >= 1, `omittedOptional=${omitted}`);
  } catch (e: any) {
    check(`${model} generateObject`, false, String(e?.message ?? e).slice(0, 200));
  }
}

async function bug3() {
  const adapter = new GoogleGeminiAdapter();
  for (const [model, expectStyle] of [['gemini-2.5-flash', 'thinking_budget'], ['gemini-3.1-flash-lite', 'thinking_level']] as const) {
    console.log(`\n### BUG 3 — Gemini thinking via google adapter: ${model}`);
    const route = resolveModelRoute(`google/${model}`, 'extraction', 'medium', { supportsReasoningControls: true, supportsVision: true })!;
    check(`${model} geminiThinkingStyle derived`, route.geminiThinkingStyle === expectStyle, `got=${route.geminiThinkingStyle}`);
    // VISION (generateText + image + reasoningEffort=medium) — the call that 400'd before
    try {
      const t0 = Date.now();
      const r = await adapter.generateText({
        plan: plan('Transcribe the image faithfully.', 'Transcribe this image.'),
        route,
        providerOptions: { messages: [{ role: 'user', content: [{ type: 'image', data: PNG, mimeType: 'image/png' }, { type: 'text', text: 'Reply with the single word: ok' }] }] },
      });
      check(`${model} VISION (image+effort) no thinking-400`, typeof r.text === 'string', `${Date.now()-t0}ms thoughtsTok=${r.usage.reasoningTokens ?? 0}`);
    } catch (e: any) {
      check(`${model} VISION (image+effort)`, false, String(e?.message ?? e).slice(0, 200));
    }
    // EXTRACTION (generateObject + reasoningEffort)
    try {
      const t0 = Date.now();
      const r = await adapter.generateObject({ plan: plan(EXTRACTION_SYSTEM_PROMPT, TRANSCRIPT), route, schema: ExtractionOutputSchema as any });
      const n = Array.isArray((r.object as any)?.claims) ? (r.object as any).claims.length : -1;
      check(`${model} EXTRACTION (effort) completes`, n >= 1, `claims=${n} ${Date.now()-t0}ms`);
    } catch (e: any) {
      check(`${model} EXTRACTION (effort)`, false, String(e?.message ?? e).slice(0, 200));
    }
  }
}

async function main() {
  if (process.env.OPENAI_API_KEY) { await bug1('gpt-4o-mini'); await bug1('gpt-4.1-mini'); }
  else console.log('SKIP bug1 — no OPENAI_API_KEY');
  if (process.env.GEMINI_API_KEY) { await bug3(); }
  else console.log('SKIP bug3 — no GEMINI_API_KEY');
  console.log(`\n=== ${failures === 0 ? 'ALL PASS' : failures + ' FAILURE(S)'} ===`);
  process.exit(failures === 0 ? 0 : 1);
}
main();
EOF
export OPENAI_API_KEY="$(op read op://vibe_coding/ai-provider-api-keys/openai)"
export GEMINI_API_KEY="$(op read op://vibe_coding/ai-provider-api-keys/gemini)"
